import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { showNotification } from '../assets/notifications';
import { useNavigationWithDelay } from '../hooks/useNavigationWithDelay';
import Loading from '../components/Loading';

interface CartItem {
  _id: string;
  title: string;
  description: string;
  price: number;
  originalPrice?: number;
  discount?: number;
  platform: string;
  image: string;
  region: string;
  availability: string;
  category: string;
}

interface Order {
  _id: string;
  user: {
    email: string;
    firstName: string;
    lastName: string;
  };
  games: Array<{
    game: {
      _id: string;
      title: string;
      platform: string;
      price: number;
    };
    price: number;
  }>;
  totalAmount: number;
  status: string;
  createdAt: string;
}

const Cart: React.FC = () => {
  const { state } = useAuth();
  const { navigateWithDelay, isLoading } = useNavigationWithDelay();
  const [orders, setOrders] = useState<Order[]>([]);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (state.isAuthenticated) {
      fetchOrders();
      loadCartItems();
    }
  }, [state.isAuthenticated]);

  const loadCartItems = () => {
    try {
      const cart = JSON.parse(localStorage.getItem('cart') || '[]');
      setCartItems(cart);
    } catch (error) {
      console.error('Error loading cart items:', error);
      setCartItems([]);
    }
  };

  const removeFromCart = (itemId: string) => {
    const updatedCart = cartItems.filter(item => item._id !== itemId);
    setCartItems(updatedCart);
    localStorage.setItem('cart', JSON.stringify(updatedCart));
    showNotification('تم حذف المنتج من السلة', 'info');
  };

  const clearCart = () => {
    setCartItems([]);
    localStorage.removeItem('cart');
    showNotification('تم تفريغ السلة', 'info');
  };

  const getTotalPrice = () => {
    return cartItems.reduce((total, item) => total + item.price, 0);
  };

  const fetchOrders = async () => {
    try {
      setLoading(true);
      // استخدام بيانات وهمية للـ orders
      const mockOrders: Order[] = [];
      setOrders(mockOrders);
    } catch (error) {
      console.error('Error fetching orders:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!state.isAuthenticated) {
    return (
      <>
        {isLoading && <Loading />}
        <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: '#0a0a0a' }}>
        <div className="card p-8 max-w-md w-full text-center">
          <div className="w-16 h-16 bg-red-600 rounded-xl flex items-center justify-center mx-auto mb-6">
            <span className="text-white font-bold text-2xl">A</span>
          </div>
          <h1 className="text-2xl font-bold text-white mb-4">يرجى تسجيل الدخول</h1>
          <p className="text-gray-400 mb-6">يجب تسجيل الدخول لعرض طلباتك</p>
          <Link to="/login" className="btn-primary inline-block">
            تسجيل الدخول
          </Link>
        </div>
      </div>
      </>
    );
  }

  return (
    <>
      {isLoading && <Loading />}
      <div className="min-h-screen" style={{ backgroundColor: '#0a0a0a' }}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <h1 className="text-3xl font-bold text-white mb-8">🛒 سلة المشتريات</h1>

        {/* Cart Items Section */}
        <div className="mb-12">
          <h2 className="text-2xl font-semibold text-white mb-6">المنتجات في السلة ({cartItems.length})</h2>

          {cartItems.length === 0 ? (
            <div className="text-center py-12 bg-gray-800 rounded-xl">
              <div className="w-20 h-20 bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-10 h-10 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
                </svg>
              </div>
              <h3 className="text-xl font-semibold text-white mb-2">السلة فارغة</h3>
              <p className="text-gray-400 mb-6">لم تقم بإضافة أي منتجات بعد</p>
              <Link to="/" className="btn-primary inline-block">
                استكشف الألعاب
              </Link>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
              {cartItems.map((item) => (
                <div key={item._id} className="bg-gray-800 rounded-xl overflow-hidden shadow-xl hover:shadow-2xl transition-all duration-300 group">
                  {/* Product Image */}
                  <div className="relative h-48 overflow-hidden">
                    <img
                      src={item.image}
                      alt={item.title}
                      className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                    />
                    {item.discount && (
                      <div className="absolute top-3 right-3 bg-red-600 text-white px-3 py-1 rounded-full text-sm font-bold">
                        -{item.discount}%
                      </div>
                    )}
                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                  </div>

                  {/* Product Info */}
                  <div className="p-4">
                    <h3 className="text-white font-bold text-lg mb-2 line-clamp-1">{item.title}</h3>
                    <p className="text-gray-400 text-sm mb-3 line-clamp-2">{item.description}</p>

                    <div className="flex justify-between items-center mb-3">
                      <div>
                        {item.originalPrice && (
                          <span className="text-gray-500 line-through text-sm block">
                            ${item.originalPrice}
                          </span>
                        )}
                        <span className="text-green-400 font-bold text-xl">${item.price}</span>
                      </div>
                      {item.discount && (
                        <span className="text-green-400 text-sm">Save {item.discount}%</span>
                      )}
                    </div>

                    <div className="flex justify-between text-sm text-gray-400 mb-4">
                      <span>🎮 {item.platform}</span>
                      <span>🌍 {item.region}</span>
                    </div>

                    <div className="flex space-x-2">
                      <button
                        onClick={() => removeFromCart(item._id)}
                        className="flex-1 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition-colors text-sm"
                      >
                        حذف
                      </button>
                      <Link
                        to={`/game/${item._id}`}
                        className="bg-gray-700 text-white px-4 py-2 rounded-lg hover:bg-gray-600 transition-colors text-sm"
                      >
                        عرض
                      </Link>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {cartItems.length > 0 && (
            <div className="bg-gray-800 rounded-xl p-6">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-semibold text-white">المجموع:</h3>
                <span className="text-2xl font-bold text-green-400">${getTotalPrice().toFixed(2)}</span>
              </div>
              <div className="flex space-x-4">
                <button
                  onClick={clearCart}
                  className="px-6 py-3 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-colors"
                >
                  تفريغ السلة
                </button>
                <button className="flex-1 px-6 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors font-semibold">
                  إتمام الطلب
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Orders Section */}
        <div>
          <h2 className="text-2xl font-semibold text-white mb-6">الطلبات السابقة</h2>

          {loading ? (
            <div className="text-center py-16">
              <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-red-600"></div>
              <p className="text-gray-400 mt-4">جاري التحميل...</p>
            </div>
          ) : orders.length > 0 ? (
            <div className="space-y-6">
              {orders.map((order) => (
                <div key={order._id} className="card p-6">
                  <div className="flex justify-between items-start mb-6">
                    <div>
                      <h3 className="text-lg font-semibold text-white">طلب #{order._id.slice(-6)}</h3>
                      <p className="text-sm text-gray-400">التاريخ: {new Date(order.createdAt).toLocaleDateString('ar-SA')}</p>
                    </div>
                    <span className={`px-3 py-1 text-sm rounded-full ${
                      order.status === 'pending' ? 'bg-yellow-600 text-white' :
                      order.status === 'completed' ? 'bg-green-600 text-white' :
                      'bg-red-600 text-white'
                    }`}>
                      {order.status === 'pending' ? 'قيد الانتظار' :
                       order.status === 'completed' ? 'مكتمل' : 'ملغي'}
                    </span>
                  </div>

                  <div className="space-y-4">
                    {order.games.map((item, index) => (
                      <div key={index} className="flex justify-between items-center p-3 bg-gray-800 rounded-lg">
                        <div>
                          <h4 className="text-white font-medium">{item.game.title}</h4>
                          <p className="text-gray-400 text-sm">{item.game.platform}</p>
                        </div>
                        <span className="text-green-400 font-medium">${item.price}</span>
                      </div>
                    ))}
                  </div>

                  <div className="mt-6 pt-6 border-t border-gray-700">
                    <div className="flex justify-between items-center">
                      <span className="text-gray-400">المجموع:</span>
                      <span className="text-xl font-bold text-green-400">${order.totalAmount}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-12 bg-gray-800 rounded-xl">
              <div className="w-20 h-20 bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-10 h-10 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
                </svg>
              </div>
              <h3 className="text-xl font-semibold text-white mb-2">لا توجد طلبات</h3>
              <p className="text-gray-400">لم تقم بإنشاء أي طلبات بعد</p>
            </div>
          )}
        </div>
      </div>
      </div>
    </>
  );
};

export default Cart;
